import { useState, useEffect } from 'react';
import { computePreview, toGrams, UNITS, unitLabel } from './nutrition';

const CATEGORY_EMOJI = {
  protein: '🥩', dairy: '🥛', grain: '🌾', vegetable: '🥦',
  fruit: '🍎', fat: '🫒', beverage: '☕', supplement: '💊', other: '🟤',
};

export default function ServingEditorModal({ food, meals, onLog, onBack }) {
  const [amount, setAmount]   = useState(1);
  const [unit, setUnit]       = useState('serving');
  const [mealId, setMealId]   = useState(meals[0]?.id ?? 1);

  useEffect(() => {
    setUnit('serving');
    setAmount(1);
  }, [food]);

  const amountG  = toGrams(Number(amount) || 0, unit, food.servingSizeG);
  const preview  = computePreview(food, amountG);
  const label    = unitLabel(Number(amount) || 0, unit);
  const canLog   = amountG > 0;

  function handleLog() {
    if (!canLog) return;
    onLog({
      foodId:           food.id,
      mealId:           Number(mealId),
      amountG,
      unitLabel:        label,
      foodName:         food.name,
      foodKcal:         food.kcal,
      foodProteinG:     food.proteinG,
      foodCarbsG:       food.carbsG,
      foodFatG:         food.fatG,
      foodFiberG:       food.fiberG      || 0,
      foodSodiumMg:     food.sodiumMg    || 0,
      foodCalciumMg:    food.calciumMg   || 0,
      foodIronMg:       food.ironMg      || 0,
      foodMagnesiumMg:  food.magnesiumMg || 0,
      foodPotassiumMg:  food.potassiumMg || 0,
      foodZincMg:       food.zincMg      || 0,
      foodCopperMg:     food.copperMg    || 0,
      foodSeleniumMcg:  food.seleniumMcg || 0,
      foodVitaminAMcg:  food.vitaminAMcg || 0,
      foodVitaminCMg:   food.vitaminCMg  || 0,
      foodVitaminDMcg:  food.vitaminDMcg || 0,
      foodVitaminEMg:   food.vitaminEMg  || 0,
      foodVitaminKMcg:  food.vitaminKMcg || 0,
      foodThiamineMg:   food.thiamineMg  || 0,
      foodRiboflavinMg: food.riboflavinMg|| 0,
      foodNiacinMg:     food.niacinMg    || 0,
      foodB6Mg:         food.b6Mg        || 0,
      foodFolateMcg:    food.folateMcg   || 0,
      foodB12Mcg:       food.b12Mcg      || 0,
      foodOmega3G:      food.omega3G     || 0,
      foodOmega6G:      food.omega6G     || 0,
      foodCategory:     food.category,
    });
  }

  const emoji = CATEGORY_EMOJI[food.category] || '🍽️';

  return (
    <div className="nc-serving">
      <div className="nc-serving-header">
        <div className={`nc-serving-icon cat-${food.category}`}>{emoji}</div>
        <div>
          <div className="nc-serving-food-name">{food.name}</div>
          {food.brand && <div className="nc-serving-food-brand">{food.brand}</div>}
          <div className="nc-serving-food-brand" style={{ color: 'var(--nc-text3)', marginTop: 2 }}>
            {food.kcal} kcal / 100 g
          </div>
        </div>
      </div>

      <div className="nc-serving-body">
        <div>
          <div className="nc-serving-label">Amount</div>
          <div className="nc-amount-row">
            <input
              className="nc-amount-input"
              type="number"
              min="0"
              step="0.5"
              value={amount}
              onChange={e => setAmount(e.target.value)}
              inputMode="decimal"
            />
            <select
              className="nc-unit-select"
              value={unit}
              onChange={e => setUnit(e.target.value)}
            >
              {UNITS.map(u => (
                <option key={u} value={u}>{u === 'serving' ? `serving (${food.servingSizeG}g)` : u}</option>
              ))}
            </select>
          </div>
        </div>

        <div>
          <div className="nc-serving-label">Meal</div>
          <select
            className="nc-meal-select"
            value={mealId}
            onChange={e => setMealId(e.target.value)}
          >
            {meals.map(m => (
              <option key={m.id} value={m.id}>{m.name}</option>
            ))}
          </select>
        </div>

        <div>
          <div className="nc-serving-label">Nutrition for {label}</div>
          <div className="nc-preview-grid">
            <div className="nc-preview-card">
              <div className="nc-preview-val">{preview.kcal}</div>
              <div className="nc-preview-lbl">kcal</div>
            </div>
            <div className="nc-preview-card">
              <div className="nc-preview-val">{preview.proteinG}g</div>
              <div className="nc-preview-lbl">protein</div>
            </div>
            <div className="nc-preview-card">
              <div className="nc-preview-val">{preview.carbsG}g</div>
              <div className="nc-preview-lbl">carbs</div>
            </div>
            <div className="nc-preview-card">
              <div className="nc-preview-val">{preview.fatG}g</div>
              <div className="nc-preview-lbl">fat</div>
            </div>
          </div>
        </div>
      </div>

      <div className="nc-serving-footer">
        <button className="nc-log-btn" onClick={handleLog} disabled={!canLog}>
          Log to Diary
        </button>
        <button
          style={{ width: '100%', marginTop: 10, padding: '10px', color: 'var(--nc-text2)', fontSize: 14 }}
          onClick={onBack}
        >
          ← Back to Search
        </button>
      </div>
    </div>
  );
}
