export default function NavBar({ tabs, activeId, onSelect, iconSize = 20 }) {
  return (
    <nav className="app-nav">
      {tabs.map(({ id, label, Icon }) => (
        <button
          key={id}
          className={`app-nav-btn${activeId === id ? ' active' : ''}`}
          onClick={() => onSelect(id)}
        >
          <Icon size={iconSize} />
          <span>{label}</span>
        </button>
      ))}
    </nav>
  );
}
